import * as React from "react";
import styled from "styled-components";
import { SubmitButton } from "../components/ButtonLink";
import { Footer } from "../helpers/footer";
import {
  FormSection,
  FormSectionTitle,
  FormText,
  FormTitle,
} from "../helpers/form-sections";
import { MainHeader } from "../helpers/header";
import { SeoComponent } from "../helpers/seoComponent";
import { Link } from "gatsby";
import trading_l from "../assets/trading_l.png";
import { media } from "../helpers/media-queries";

// markup
const ResponseOkPage = () => {
  return (
    <SeoComponent>
      <main>
        <MainHeader dark />
        <FormSection>
          <div>
            <FormTitle>Thank you for contacting us</FormTitle>
            <FormText>We will get in touch with you soon.</FormText>
            <Link href="/">
              <StyledSubmitButton>Back to homepage</StyledSubmitButton>
            </Link>
          </div>
          <ImageWrapper>
            <StyledPicture>
              <source media="(min-width: 1366px)" srcSet={trading_l} />
              <source media="(min-width: 768px)" srcSet={trading_l} />
              <ResponsiveImg src={trading_l} />
            </StyledPicture>
          </ImageWrapper>
        </FormSection>
        <Footer />
      </main>
    </SeoComponent>
  );
};

export default ResponseOkPage;

const StyledSubmitButton = styled(SubmitButton)`
  margin-top: 42px;
  width: 280px;
`;

const ImageWrapper = styled.div`
  margin-top: 64px;

  ${media.m`
    margin-top: 0;
  `}
`;

const ResponsiveImg = styled.img`
  width: 100%;

  ${media.m`
    max-width: 593px;
  `}

  ${media.l`
    max-width: 850px;
  `}
`;

const StyledPicture = styled.picture`
  display: flex;
  position: relative;

  &::before {
    content: "";
    background: #4449e4;
    position: absolute;
    top: -10px;
    right: -10px;
    width: 75%;
    height: 10px;
  }

  &::after {
    content: "";
    background: #4449e4;
    position: absolute;
    top: -10px;
    right: -10px;
    height: 90%;
    width: 10px;
  }
`;
